@@ -0,0 +1,305 @@
+const std = @import("std");
+const llama = @import("llama.zig");
+const profile_mod = @import("profile.zig");
+const c = llama.c;
+
+/// Context tier sizes
+pub const TIER_SIZES = [4]u32{ 512, 1024, 2048, 4096 };
+
+/// Pooled context wrapper with lifecycle tracking
+pub const PooledContext = struct {
+    ctx: llama.Context,
+    tier: usize, // 0=512, 1=1024, 2=2048, 3=4096
+    n_ctx: u32,
+    in_use: bool,
+    last_used: i64,
+    usage_count: usize,
+
+    pub fn init(
+        model: *llama.Model,
+        tier: usize,
+        profile: profile_mod.Profile,
+    ) !PooledContext {
+        if (tier >= TIER_SIZES.len) {
+            return error.InvalidTier;
+        }
+
+        const n_ctx = TIER_SIZES[tier];
+
+        // Create context with tier-specific size
+        var prof_copy = profile;
+        prof_copy.optimal_config.n_ctx = n_ctx;
+
+        var ctx = try llama.initContextWithProfile(model, prof_copy);
+
+        return PooledContext{
+            .ctx = ctx,
+            .tier = tier,
+            .n_ctx = n_ctx,
+            .in_use = false,
+            .last_used = 0,
+            .usage_count = 0,
+        };
+    }
+
+    pub fn deinit(self: *PooledContext) void {
+        self.ctx.deinit();
+    }
+
+    pub fn markUsed(self: *PooledContext) void {
+        self.in_use = true;
+        self.last_used = std.time.timestamp();
+        self.usage_count += 1;
+    }
+
+    pub fn markAvailable(self: *PooledContext) void {
+        self.in_use = false;
+    }
+};
+
+/// Context tier configuration
+pub const ContextTier = struct {
+    size: u32,
+    capacity: usize, // Max number of contexts to pre-create
+    contexts: std.ArrayList(*PooledContext),
+
+    pub fn init(allocator: std.mem.Allocator, size: u32, capacity: usize) !ContextTier {
+        return ContextTier{
+            .size = size,
+            .capacity = capacity,
+            .contexts = std.ArrayList(*PooledContext).init(allocator),
+        };
+    }
+
+    pub fn deinit(self: *ContextTier, allocator: std.mem.Allocator) void {
+        for (self.contexts.items) |ctx| {
+            ctx.deinit();
+            allocator.destroy(ctx);
+        }
+        self.contexts.deinit();
+    }
+};
+
+/// Multi-tier context pool with lifecycle management
+pub const ContextPool = struct {
+    allocator: std.mem.Allocator,
+    tiers: [4]ContextTier,
+    in_use: std.ArrayList(*PooledContext),
+    model: *llama.Model,
+    profile: profile_mod.Profile,
+
+    /// Initialize context pool with memory-aware tier allocation
+    pub fn init(
+        allocator: std.mem.Allocator,
+        model: *llama.Model,
+        profile: profile_mod.Profile,
+    ) !ContextPool {
+        // Calculate tier capacities based on available memory
+        // For 8GB available:
+        // - Tier 0 (512):  4 contexts @ 0.5GB = 2.0GB
+        // - Tier 1 (1024): 2 contexts @ 1.0GB = 2.0GB
+        // - Tier 2 (2048): 1 context  @ 2.0GB = 2.0GB
+        // - Tier 3 (4096): 1 context  @ 4.0GB = 4.0GB
+        // Total: 10GB (with 2GB headroom for migrations)
+
+        const tier_capacities = calculateTierCapacities(profile.memory_estimate.headroom_gb);
+
+        var tiers: [4]ContextTier = undefined;
+        for (TIER_SIZES, 0..) |size, i| {
+            tiers[i] = try ContextTier.init(allocator, size, tier_capacities[i]);
+        }
+
+        return ContextPool{
+            .allocator = allocator,
+            .tiers = tiers,
+            .in_use = std.ArrayList(*PooledContext).init(allocator),
+            .model = model,
+            .profile = profile,
+        };
+    }
+
+    pub fn deinit(self: *ContextPool) void {
+        for (&self.tiers) |*tier| {
+            tier.deinit(self.allocator);
+        }
+        self.in_use.deinit();
+    }
+
+    /// Acquire a context from the specified tier
+    pub fn acquire(self: *ContextPool, tier: usize) !*PooledContext {
+        if (tier >= self.tiers.len) {
+            return error.InvalidTier;
+        }
+
+        var tier_obj = &self.tiers[tier];
+
+        // Look for available context in tier
+        for (tier_obj.contexts.items) |ctx| {
+            if (!ctx.in_use) {
+                ctx.markUsed();
+                try self.in_use.append(ctx);
+                return ctx;
+            }
+        }
+
+        // No available contexts, create new if under capacity
+        if (tier_obj.contexts.items.len < tier_obj.capacity) {
+            var ctx_ptr = try self.allocator.create(PooledContext);
+            errdefer self.allocator.destroy(ctx_ptr);
+
+            ctx_ptr.* = try PooledContext.init(self.model, tier, self.profile);
+            try tier_obj.contexts.append(ctx_ptr);
+
+            ctx_ptr.markUsed();
+            try self.in_use.append(ctx_ptr);
+            return ctx_ptr;
+        }
+
+        // At capacity, need to wait or fail
+        return error.TierAtCapacity;
+    }
+
+    /// Release a context back to the pool
+    pub fn release(self: *ContextPool, ctx: *PooledContext) void {
+        ctx.markAvailable();
+
+        // Remove from in_use list
+        for (self.in_use.items, 0..) |item, i| {
+            if (item == ctx) {
+                _ = self.in_use.swapRemove(i);
+                break;
+            }
+        }
+    }
+
+    /// Migrate KV cache state from one context to another
+    pub fn migrate(
+        self: *ContextPool,
+        from: *PooledContext,
+        to: *PooledContext,
+    ) !void {
+        _ = self;
+
+        // Get state size from source context
+        const state_size = from.ctx.getStateSize();
+
+        // Allocate temporary buffer for state
+        const state = try self.allocator.alloc(u8, state_size);
+        defer self.allocator.free(state);
+
+        // Extract state from source
+        try from.ctx.getState(state);
+
+        // Load state into destination
+        try to.ctx.setState(state);
+
+        // Validate migration
+        const to_state_size = to.ctx.getStateSize();
+        if (to_state_size != state_size) {
+            std.debug.print("Warning: State size mismatch after migration\n", .{});
+            std.debug.print("  Expected: {}, Got: {}\n", .{ state_size, to_state_size });
+        }
+    }
+
+    /// Get statistics about pool usage
+    pub fn getStats(self: *ContextPool) PoolStats {
+        var stats = PoolStats{
+            .total_contexts = 0,
+            .in_use_contexts = self.in_use.items.len,
+            .available_contexts = 0,
+            .tier_usage = [_]usize{0} ** 4,
+        };
+
+        for (self.tiers, 0..) |tier, i| {
+            stats.total_contexts += tier.contexts.items.len;
+            stats.tier_usage[i] = tier.contexts.items.len;
+
+            for (tier.contexts.items) |ctx| {
+                if (!ctx.in_use) {
+                    stats.available_contexts += 1;
+                }
+            }
+        }
+
+        return stats;
+    }
+};
+
+pub const PoolStats = struct {
+    total_contexts: usize,
+    in_use_contexts: usize,
+    available_contexts: usize,
+    tier_usage: [4]usize,
+};
+
+/// Calculate tier capacities based on available memory
+fn calculateTierCapacities(headroom_gb: f64) [4]usize {
+    // Conservative allocation: use 80% of headroom
+    const available_gb = headroom_gb * 0.8;
+
+    // Estimate memory per tier (rough approximation)
+    // Assumes fp16 KV cache, 32 layers, 4096 embd
+    const tier_memory_gb = [4]f64{
+        0.5, // Tier 0: 512 tokens
+        1.0, // Tier 1: 1024 tokens
+        2.0, // Tier 2: 2048 tokens
+        4.0, // Tier 3: 4096 tokens
+    };
+
+    var capacities: [4]usize = undefined;
+
+    if (available_gb >= 10.0) {
+        // Large memory system (16GB+ RAM)
+        capacities = [_]usize{ 4, 2, 1, 1 };
+    } else if (available_gb >= 6.0) {
+        // Medium memory system (12GB RAM)
+        capacities = [_]usize{ 3, 2, 1, 0 };
+    } else if (available_gb >= 3.0) {
+        // Small memory system (8GB RAM)
+        capacities = [_]usize{ 2, 1, 1, 0 };
+    } else {
+        // Very limited memory (4GB RAM)
+        capacities = [_]usize{ 2, 1, 0, 0 };
+    }
+
+    // Validate total memory usage
+    var total_memory: f64 = 0.0;
+    for (capacities, 0..) |capacity, i| {
+        total_memory += @as(f64, @floatFromInt(capacity)) * tier_memory_gb[i];
+    }
+
+    // If over budget, reduce capacities
+    if (total_memory > available_gb) {
+        std.debug.print(
+            "Warning: Initial tier capacities exceed memory budget ({d:.1}GB > {d:.1}GB)\n",
+            .{ total_memory, available_gb },
+        );
+        std.debug.print("Reducing capacities...\n", .{});
+
+        // Simple reduction: halve all capacities
+        for (&capacities) |*capacity| {
+            capacity.* = @max(capacity.* / 2, 1);
+        }
+    }
+
+    return capacities;
+}
+
+// Tests
+test "tier sizes" {
+    try std.testing.expectEqual(@as(usize, 4), TIER_SIZES.len);
+    try std.testing.expectEqual(@as(u32, 512), TIER_SIZES[0]);
+    try std.testing.expectEqual(@as(u32, 4096), TIER_SIZES[3]);
+}
+
+test "calculate tier capacities" {
+    // Large memory
+    const large = calculateTierCapacities(12.0);
+    try std.testing.expectEqual(@as(usize, 4), large[0]);
+    try std.testing.expectEqual(@as(usize, 1), large[3]);
+
+    // Small memory
+    const small = calculateTierCapacities(3.5);
+    try std.testing.expectEqual(@as(usize, 2), small[0]);
+    try std.testing.expectEqual(@as(usize, 0), small[3]);
+}
